package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        // Create a CSVFormat instance using the private constructor via reflection
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsEscapeCharacterSet_whenEscapeCharacterIsNull() throws Exception {
        // Set escapeCharacter field to null using reflection
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);
        escapeCharacterField.set(csvFormat, null);

        boolean result = csvFormat.isEscapeCharacterSet();

        assertFalse(result, "Escape character is null, should return false");
    }

    @Test
    public void testIsEscapeCharacterSet_whenEscapeCharacterIsSet() throws Exception {
        // Set escapeCharacter field to a non-null Character using reflection
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);
        escapeCharacterField.set(csvFormat, '\\');

        boolean result = csvFormat.isEscapeCharacterSet();

        assertTrue(result, "Escape character is set, should return true");
    }
}
